// §2.2.6 — 显示信息服务//// NAPI 方法 getDisplayInfo()，// 通过 display.getDefaultDisplaySync() 获取屏幕尺寸和密度。//// C FFI 桥（ohos_get_display_info）由 Rust 侧通过 extern "C" 调用。// 使用 TSFN 桥接在 UI 线程安全调用 NAPI，避免跨线程 abort。#include <string>#include <napi/native_api.h>#include "napi_utils.h"#undef LOG_TAG#define LOG_TAG "Display"static napi_value GetDisplayInfo(napi_env env, napi_callback_info info) {    napi_value display;    napi_value defaultDisplay;    napi_value width;    napi_value height;    napi_value density;    napi_value orientation;    // OHOS: display.getDefaultDisplaySync() 返回 Display 对象    // 使用 requireNapi 导入模块    napi_value displayModule;    napi_load_module(env, "@kit.ArkUI", &displayModule);    napi_get_named_property(env, displayModule, "display", &display);    napi_call_function(env, display, nullptr, 0, nullptr, &defaultDisplay);    napi_get_named_property(env, defaultDisplay, "width", &width);    napi_get_named_property(env, defaultDisplay, "height", &height);    napi_get_named_property(env, defaultDisplay, "density", &density);    napi_get_named_property(env, defaultDisplay, "orientation", &orientation);    // 构造 JSON 对象    napi_value obj;    napi_create_object(env, &obj);    napi_set_named_property(env, obj, "width", width);    napi_set_named_property(env, obj, "height", height);    napi_set_named_property(env, obj, "density", density);    napi_set_named_property(env, obj, "orientation", orientation);    return obj;}void RegisterDisplay(napi_env env, napi_value exports) {    OH_LOG_INFO(LOG_APP, "Display::Register called");    napi_property_descriptor desc[] = {        {"getDisplayInfo", nullptr, GetDisplayInfo, nullptr, nullptr, nullptr, napi_default, nullptr},    };    napi_define_properties(env, exports, sizeof(desc) / sizeof(desc[0]), desc);}// ── C FFI 桥：通过 TSFN 安全调用 ArkTS ───────────────────────────────────────extern "C" {extern void ohos_call_napi(const char* method, char* result, size_t max_len);const char* ohos_get_display_info() {    static thread_local std::string buf;    char result[4096] = {0};    ohos_call_napi("getDisplayInfo", result, sizeof(result));    buf = result;    return buf.c_str();}} // extern "C"